def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (bin_cap + 1e-8)
        priority = 0.0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    term1 = ((ratio - a) ** 6) / ((a + b) ** 1.5 + 1)
                    term2 = np.tanh(np.sin(ratio * b * 1.2 + i))
                    priority += term1 * term2 * np.exp(-b / (ratio + 0.1))
            priority += (np.log1p(ratio) ** 3) * np.sin(ratio * 1.7) ** 2
            if bin_cap < item * 5:
                priority += np.sqrt(bin_cap * item) * 5
            else:
                priority -= np.cos(ratio * item) * 4
        elif 7 < ratio <= 10:
            for p in range(1, 8):
                for q in range(1, p * 2):
                    frac = ((ratio - p) ** 4) / (q + 1)
                    trig = np.cos(ratio * q) * np.sin(p * ratio * 0.8)
                    priority += np.tanh(frac * trig) * 2.3
            priority += np.exp(-ratio / 10) * 15
            if bin_cap < item * 2:
                priority += 3 * np.sin(i + ratio)
            else:
                priority -= 2 * np.cos(i * ratio)
        elif 4 <= ratio <= 7:
            s1 = 0.0
            s2 = 0.0
            for r in range(2, 15):
                s1 += ((ratio - 3.5) ** r) / (r ** 2 + 1) * np.sin(r * ratio * 0.95)
            for r in range(1, 8):
                s2 += np.cos(r * ratio * 1.1) / (r + 0.7)
            priority = s1 * np.exp(-ratio / 8) - s2 + np.log(ratio + 0.1) * 7
            if (i + int(item * 2)) % 2 == 0:
                priority += np.sqrt(bin_cap) * 1.7
            else:
                priority -= np.sqrt(bin_cap) * 1.2
        elif 2 <= ratio < 4:
            sum_cos = 0
            for n in range(1, 12):
                sum_cos += ((4 - ratio) ** n) / (n + 0.5) * np.cos(n * ratio * 2.3)
            penalty = 0
            if bin_cap < item * 1.5:
                penalty = np.exp(-item / (bin_cap + 0.1)) * 12
            else:
                penalty = np.tanh(ratio) * 6
            priority = sum_cos + penalty
            for m in range(1, 6):
                priority += np.sin(m * item * ratio * 0.9) * ((ratio - 2) ** m) / (m * 1.3)
        elif 1 <= ratio < 2:
            s = 0
            for x in range(1, 20):
                s += ((2 - ratio) ** x) / (x ** 1.8 + 0.3) * np.cos(x * ratio * 0.7)
            if bin_cap < item * 1.2:
                penalty = np.cos(ratio * 10) * 4 + np.log1p(item / (bin_cap + 0.1))
            else:
                penalty = np.exp(-ratio * 5) * 8
            priority = s + penalty
            for y in range(1, 5):
                priority += np.sin(i * y + ratio * y * 1.1) * (ratio ** y) / (y + 0.8)
        elif 0.5 <= ratio < 1:
            s = 0
            for z in range(1, 18):
                s += ((1 - ratio) ** z) / (z * 3.5 + 1) * np.sin(z * ratio * 1.3 + i)
            if int(item * 2.5) % 3 == 1:
                s *= np.log(bin_cap + 3) * 1.5
            else:
                s /= (np.sqrt(bin_cap + 2) + 1.5)
            penalty = 0
            if bin_cap < item * 0.8:
                penalty = np.sqrt(item) * 3.2 / (bin_cap + 1)
            else:
                penalty = -np.cos(ratio * 15) * 3.8
            priority = s + penalty
            for w in range(1, 7):
                priority += ((1 - ratio) ** w) * np.cos(w * item * 1.4 + i) / (w + 1)
        elif 0.2 <= ratio < 0.5:
            s1 = 0
            for v in range(1, 22):
                s1 += ((0.5 - ratio) ** v) / (v * 4.2 + 1) * np.sin(v * ratio * 2 + i)
            s2 = np.log1p(bin_cap + item) / (ratio + 1e-5)
            priority = s1 + s2
            if (i * int(item * 3)) % 5 == 0:
                priority *= 2.2
            else:
                priority /= 2.2
            if bin_cap < item * 0.3:
                priority += np.sqrt(bin_cap * item) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
        else:
            residual = 0
            for u in range(1, 25):
                residual += ((0.2 - ratio) ** u) / (u * 5) * np.cos(u * ratio * item * 0.6 + i)
            penalty = 1 / (bin_cap + 2) * 10
            priority = residual + penalty
            if int(item * 0.9) % 4 == 0:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.1:
                priority += np.log1p(item + bin_cap) * 8
            else:
                priority -= np.exp(-3 * ratio) * 7
        if bin_cap < item * 0.5:
            priority += np.sqrt(item ** 3 * bin_cap + 1) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-2.5 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx * 1.5)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 1.5)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        elif i % 3 == 0:
            priority -= np.cos(ratio * i * 1.2) * 0.65
        else:
            priority += np.sin(ratio * i * 0.9) * 0.5
        priorities[i] = priority
    return priorities
